// Worked focus: cmem-explicit-clearing — Use C23 memset_explicit or a reviewed non-elidable alternative for secrets and verify compiler and library support.
/* Evidence: cmem-worked-cmem-representation-alignment-padding-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 1911; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_representation_alignment_padding_2(unsigned value, unsigned char *out, size_t capacity, unsigned *decoded) {
  if (out == NULL || decoded == NULL || capacity < 4) return 0;
  out[0] = (unsigned char)((value >> 24) & 255u);
  out[1] = (unsigned char)((value >> 16) & 255u);
  out[2] = (unsigned char)((value >> 8) & 255u);
  out[3] = (unsigned char)(value & 255u);
  *decoded = ((unsigned)out[0] << 24) | ((unsigned)out[1] << 16) |
             ((unsigned)out[2] << 8) | (unsigned)out[3];
  return 1;
}

int main(void) {
  unsigned char bytes[4];
  unsigned input = 0x10203000u + 4u;
  unsigned decoded = 0u;
  int rejected = worked_cmem_representation_alignment_padding_2(input, bytes, 3, &decoded);
  int accepted = worked_cmem_representation_alignment_padding_2(input, bytes, 4, &decoded);
  int invariant = !rejected && accepted && decoded == input && bytes[0] == 0x10u;
  printf("representation last=%u invariant=%d\n", (unsigned)bytes[3], invariant);
  return invariant ? 0 : 1;
}

